sql:
SELECT *
FROM satellite_images
WHERE value_sum > 1000 AND satellite_id < 100;

SELECT modis_date, COUNT(DISTINCT image_id) AS total_images
FROM satellite_images
GROUP BY modis_date;

SELECT product, 
       DENSE_RANK() OVER(ORDER BY value_sum DESC) AS rank
FROM satellite_images;

SELECT access_method, COUNT(image_id) as total_images
FROM user_access_logs
GROUP BY access_method;

SELECT COUNT(*) 
FROM bands
WHERE wavelength > (SELECT AVG(wavelength) FROM bands);

external_knowledge:
- "stars" refer to the satellite images;
- "shone brightly above the horizon" symbolizes the `value_min` being greater than 500;
- "brilliance" and "collective luminescence" represent the `value_max` and `value_sum`, respectively;
- "twinkling has surpassed the twilight threshold" refers to the `value_min` being greater than 500;
- "celestial catalog 'MCD15A3H'" corresponds to the `product` being 'MCD15A3H';
- "observatories numbered between the 50th and 99th" refers to `satellite_id` being between 50 and 99;
- "focused on the 'Lai_500m' constellation" refers to the `band` being 'Lai_500m'.

sql:
SELECT AVG(cloud_cover) AS Average_Cloud_Cover, AVG(sun_elevation) AS Average_Sun_Elevation
FROM satellite_images
WHERE proc_date BETWEEN '2018-03-01' AND '2019-03-01';

SELECT capture_time, cloud_cover, sun_elevation
FROM satellite_images
WHERE image_id = 'desired_image_id';

SELECT COUNT(*) AS num_images
FROM satellite_images
WHERE dt = '2020-01-01' AND value_min < 10;
